import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../services/axios';

function MyBookings() {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [paymentLoading, setPaymentLoading] = useState(false);

  useEffect(() => { fetchBookings(); }, []);

  const fetchBookings = async () => {
    try {
      const res = await API.get('/bookings/my');
      setBookings(res.data.bookings || []);
    } catch {
      setError('Failed to load bookings');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await API.put(`/bookings/${id}/cancel`, {});
      fetchBookings();
    } catch {
      alert('Failed to cancel booking');
    }
  };

  const handlePayment = async () => {
    setPaymentLoading(true);
    try {
      await API.post('/payments', { bookingId: selectedBooking._id, paymentMethod });
      setSelectedBooking(null);
      fetchBookings();
    } catch (err) {
      alert(err.response?.data?.message || 'Payment failed');
    } finally {
      setPaymentLoading(false);
    }
  };

  const statusColor = (s) => ({ confirmed: 'bg-green-100 text-green-700', pending: 'bg-yellow-100 text-yellow-700', cancelled: 'bg-red-100 text-red-700' }[s] || 'bg-gray-100 text-gray-700');
  const paymentColor = (s) => ({ paid: 'bg-green-100 text-green-700', unpaid: 'bg-red-100 text-red-700', refunded: 'bg-blue-100 text-blue-700' }[s] || 'bg-gray-100 text-gray-700');

  if (loading) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center"><div className="text-5xl mb-4 animate-bounce">🎫</div>
        <p className="text-gray-500">Loading your bookings...</p></div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">

      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-purple-600 py-10">
        <div className="max-w-6xl mx-auto px-4">
          <h1 className="text-4xl font-bold text-white">My Bookings</h1>
          <p className="text-white/80 mt-1">{bookings.length} booking(s) total</p>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 py-8">
        {error && <div className="bg-red-50 text-red-700 px-4 py-3 rounded-xl mb-6">⚠️ {error}</div>}

        {bookings.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-sm p-16 text-center">
            <div className="text-6xl mb-4">🎫</div>
            <h2 className="text-2xl font-bold text-gray-700 mb-2">No bookings yet</h2>
            <p className="text-gray-500 mb-6">Explore events and book your first ticket!</p>
            <Link to="/home" className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-3 rounded-xl font-semibold hover:shadow-lg transition">
              Browse Events
            </Link>
          </div>
        ) : (
          <div className="space-y-4">
            {bookings.map(booking => (
              <div key={booking._id} className="bg-white rounded-2xl shadow-sm p-6 hover:shadow-md transition">
                <div className="flex flex-col md:flex-row gap-6">

                  {/* Event Image */}
                  <img src={booking.event?.image || 'https://via.placeholder.com/200x130?text=Event'}
                    alt={booking.event?.name} className="w-full md:w-40 h-32 object-cover rounded-xl" />

                  {/* Details */}
                  <div className="flex-1">
                    <div className="flex justify-between items-start flex-wrap gap-2">
                      <h3 className="text-xl font-bold text-gray-800">{booking.event?.name}</h3>
                      <span className="font-mono text-xs text-gray-400">#{booking._id.slice(-8).toUpperCase()}</span>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mt-3">
                      {[
                        { label: '📅 Date', value: booking.event?.date ? new Date(booking.event.date).toLocaleDateString('en-IN') : 'N/A' },
                        { label: '📍 Venue', value: booking.event?.venue || 'N/A' },
                        { label: '🎫 Tickets', value: booking.numberOfTickets },
                        { label: '💰 Total', value: `₹${booking.totalAmount}` },
                      ].map(item => (
                        <div key={item.label} className="bg-gray-50 rounded-xl p-3">
                          <p className="text-xs text-gray-400">{item.label}</p>
                          <p className="font-semibold text-gray-700 text-sm">{item.value}</p>
                        </div>
                      ))}
                    </div>

                    <div className="flex items-center justify-between mt-4 flex-wrap gap-3">
                      <div className="flex gap-2">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${statusColor(booking.status)}`}>
                          {booking.status.toUpperCase()}
                        </span>
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${paymentColor(booking.paymentStatus)}`}>
                          {booking.paymentStatus.toUpperCase()}
                        </span>
                      </div>

                      <div className="flex gap-2">
                        {booking.paymentStatus === 'unpaid' && booking.status !== 'cancelled' && (
                          <button onClick={() => setSelectedBooking(booking)}
                            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-xl text-sm font-semibold transition">
                            💳 Pay Now
                          </button>
                        )}
                        {booking.status !== 'cancelled' && (
                          <button onClick={() => handleCancel(booking._id)}
                            className="bg-red-50 hover:bg-red-100 text-red-600 px-4 py-2 rounded-xl text-sm font-semibold transition">
                            Cancel
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Payment Modal */}
      {selectedBooking && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 px-4">
          <div className="bg-white rounded-2xl shadow-2xl p-8 w-full max-w-md">
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Complete Payment</h2>
            <p className="text-gray-500 mb-6">{selectedBooking.event?.name}</p>

            <div className="bg-gray-50 rounded-xl p-4 mb-6">
              <div className="flex justify-between text-sm text-gray-600 mb-1">
                <span>Tickets</span><span>{selectedBooking.numberOfTickets}</span>
              </div>
              <div className="flex justify-between font-bold text-gray-800 border-t pt-2">
                <span>Total Amount</span>
                <span className="text-blue-600">₹{selectedBooking.totalAmount}</span>
              </div>
            </div>

            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-3">Payment Method</label>
              <div className="grid grid-cols-2 gap-3">
                {[
                  { value: 'card', icon: '💳', label: 'Card' },
                  { value: 'upi', icon: '📱', label: 'UPI' },
                  { value: 'netbanking', icon: '🏦', label: 'Net Banking' },
                  { value: 'wallet', icon: '👛', label: 'Wallet' },
                ].map(method => (
                  <button key={method.value} onClick={() => setPaymentMethod(method.value)}
                    className={`p-3 rounded-xl border-2 font-medium text-sm transition ${
                      paymentMethod === method.value
                        ? 'border-blue-500 bg-blue-50 text-blue-700'
                        : 'border-gray-200 hover:border-gray-300'
                    }`}>
                    {method.icon} {method.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-3">
              <button onClick={() => setSelectedBooking(null)}
                className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 py-3 rounded-xl font-semibold transition">
                Cancel
              </button>
              <button onClick={handlePayment} disabled={paymentLoading}
                className="flex-1 bg-gradient-to-r from-blue-600 to-purple-600 text-white py-3 rounded-xl font-semibold hover:shadow-lg transition disabled:opacity-50">
                {paymentLoading ? '⏳ Processing...' : '✅ Pay Now'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default MyBookings;
